-- Sprint 44: Expand registry_surfaces_catalog and validation_repair to match sqlAdapter SHEET_COLUMNS
-- migration 039 created both tables with minimal schemas. This adds the remaining columns.

-- ── 1. registry_surfaces_catalog — add 21 missing columns ──────────────────────
ALTER TABLE `registry_surfaces_catalog`
  ADD COLUMN IF NOT EXISTS `surface_type`                    VARCHAR(100) NULL AFTER `surface_name`,
  ADD COLUMN IF NOT EXISTS `surface_scope`                   VARCHAR(100) NULL AFTER `surface_type`,
  ADD COLUMN IF NOT EXISTS `storage_type`                    VARCHAR(100) NULL AFTER `surface_scope`,
  ADD COLUMN IF NOT EXISTS `file_id`                         VARCHAR(255) NULL AFTER `storage_type`,
  ADD COLUMN IF NOT EXISTS `folder_id`                       VARCHAR(255) NULL AFTER `file_id`,
  ADD COLUMN IF NOT EXISTS `parent_surface_id`               VARCHAR(255) NULL AFTER `folder_id`,
  ADD COLUMN IF NOT EXISTS `resolution_rule`                 VARCHAR(255) NULL AFTER `required_for_execution`,
  ADD COLUMN IF NOT EXISTS `owner_layer`                     VARCHAR(100) NULL AFTER `resolution_rule`,
  ADD COLUMN IF NOT EXISTS `notes`                           TEXT         NULL AFTER `owner_layer`,
  ADD COLUMN IF NOT EXISTS `formula_audit_required`          VARCHAR(20)  NULL AFTER `audit_mode`,
  ADD COLUMN IF NOT EXISTS `projection_audit_required`       VARCHAR(20)  NULL AFTER `formula_audit_required`,
  ADD COLUMN IF NOT EXISTS `control_metric_audit_required`   VARCHAR(20)  NULL AFTER `projection_audit_required`,
  ADD COLUMN IF NOT EXISTS `write_target_audit_required`     VARCHAR(20)  NULL AFTER `control_metric_audit_required`,
  ADD COLUMN IF NOT EXISTS `source_surface_id`               VARCHAR(255) NULL AFTER `legacy_surface_containment_required`,
  ADD COLUMN IF NOT EXISTS `source_surface_role`             VARCHAR(100) NULL AFTER `source_surface_id`,
  ADD COLUMN IF NOT EXISTS `retired_replacement_surface_id`  VARCHAR(255) NULL AFTER `source_surface_role`,
  ADD COLUMN IF NOT EXISTS `logical_surface_key`             VARCHAR(255) NULL AFTER `retired_replacement_surface_id`,
  ADD COLUMN IF NOT EXISTS `backend_type`                    VARCHAR(100) NULL AFTER `logical_surface_key`,
  ADD COLUMN IF NOT EXISTS `backend_adapter`                 VARCHAR(100) NULL AFTER `backend_type`,
  ADD COLUMN IF NOT EXISTS `authority_model`                 VARCHAR(100) NULL AFTER `backend_adapter`,
  ADD COLUMN IF NOT EXISTS `portability_class`               VARCHAR(100) NULL AFTER `authority_model`;

